import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from flask_cors import CORS
import os
import uuid
from werkzeug.utils import secure_filename
from sklearn.preprocessing import LabelEncoder
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.applications import ResNet50
from tensorflow.keras.layers import Dense, GlobalAveragePooling2D
from tensorflow.keras.models import Model
import cv2
from PIL import Image
import io

app = Flask(__name__)
CORS(app)

UPLOAD_FOLDER = 'uploads'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
MODEL_PATH = 'community_model.h5'

# Global variables for model and training data
model = None
label_encoder = None
training_data = []

def create_model(num_classes):
    base_model = ResNet50(weights='imagenet', include_top=False, input_shape=(224, 224, 3))
    x = base_model.output
    x = GlobalAveragePooling2D()(x)
    x = Dense(1024, activation='relu')(x)
    predictions = Dense(num_classes, activation='softmax')(x)
    model = Model(inputs=base_model.input, outputs=predictions)
    
    for layer in base_model.layers:
        layer.trainable = False
    
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

def load_and_preprocess_data(csv_path, image_folder):
    df = pd.read_csv(csv_path)
    images = []
    labels = []
    
    for index, row in df.iterrows():
        try:
            img_path = os.path.join(image_folder, row['image_name'])
            img = cv2.imread(img_path)
            img = cv2.resize(img, (224, 224))
            img = img / 255.0
            images.append(img)
            labels.append(row['label'])
        except Exception as e:
            print(f"Error loading image {row['image_name']}: {e}")
            continue
    
    return np.array(images), np.array(labels)

def train_model():
    global model, label_encoder
    
    if len(training_data) < 2:
        return False
    
    # Create label encoder
    label_encoder = LabelEncoder()
    labels = [item['label'] for item in training_data]
    encoded_labels = label_encoder.fit_transform(labels)
    
    # Convert labels to categorical
    num_classes = len(np.unique(encoded_labels))
    categorical_labels = tf.keras.utils.to_categorical(encoded_labels, num_classes)
    
    # Create model
    model = create_model(num_classes)
    
    # Prepare data
    images = []
    for item in training_data:
        try:
            img = cv2.imread(item['image_path'])
            img = cv2.resize(img, (224, 224))
            img = img / 255.0
            images.append(img)
        except Exception as e:
            print(f"Error loading image {item['image_path']}: {e}")
            continue
    
    if not images:
        return False
    
    images = np.array(images)
    
    # Train model
    model.fit(images, categorical_labels, epochs=5, batch_size=32, validation_split=0.2)
    
    # Save model
    model.save(MODEL_PATH)
    return True

@app.route('/upload', methods=['POST'])
def upload_file():
    global training_data
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    label = request.form.get('label', 'unknown')
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file:
        filename = secure_filename(file.filename)
        unique_filename = f"{uuid.uuid4()}_{filename}"
        file_path = os.path.join(UPLOAD_FOLDER, unique_filename)
        file.save(file_path)
        
        # Add to training data
        training_data.append({
            'image_path': file_path,
            'label': label
        })
        
        return jsonify({'message': 'File uploaded successfully', 'filename': unique_filename})
    
    return jsonify({'error': 'Upload failed'}), 500

@app.route('/train', methods=['POST'])
def train():
    try:
        success = train_model()
        if success:
            return jsonify({'message': 'Model trained successfully'})
        else:
            return jsonify({'error': 'Not enough training data'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    global model, label_encoder
    
    if model is None or label_encoder is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file:
        try:
            # Read image
            img = Image.open(file.stream)
            img = img.convert('RGB')
            img = img.resize((224, 224))
            img_array = np.array(img)
            img_array = img_array / 255.0
            img_array = np.expand_dims(img_array, axis=0)
            
            # Make prediction
            predictions = model.predict(img_array)
            predicted_class = np.argmax(predictions[0])
            confidence = predictions[0][predicted_class]
            
            # Decode label
            predicted_label = label_encoder.inverse_transform([predicted_class])[0]
            
            return jsonify({
                'prediction': predicted_label,
                'confidence': float(confidence)
            })
            
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Prediction failed'}), 500

@app.route('/status', methods=['GET'])
def status():
    return jsonify({
        'model_trained': model is not None,
        'training_examples': len(training_data)
    })

if __name__ == '__main__':
    app.run(debug=True)